import{_ as e,o as l,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"貨櫃航運聯盟結構與競爭動態（2025-2026）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-7_聯盟結構與競爭動態.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-7_聯盟結構與競爭動態.md"}'),o={name:"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-7_聯盟結構與競爭動態.md"};function n(t,a,s,g,h,c){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="貨櫃航運聯盟結構與競爭動態-2025-2026" tabindex="-1">貨櫃航運聯盟結構與競爭動態（2025-2026） <a class="header-anchor" href="#貨櫃航運聯盟結構與競爭動態-2025-2026" aria-label="Permalink to &quot;貨櫃航運聯盟結構與競爭動態（2025-2026）&quot;">​</a></h1><h2 id="聯盟格局重大重組" tabindex="-1">聯盟格局重大重組 <a class="header-anchor" href="#聯盟格局重大重組" aria-label="Permalink to &quot;聯盟格局重大重組&quot;">​</a></h2><p>2025年是貨櫃航運聯盟歷史上的分水嶺。經過十餘年的聯盟競爭後，2025年初發生了根本性重組：</p><h3 id="解體的舊聯盟" tabindex="-1">解體的舊聯盟 <a class="header-anchor" href="#解體的舊聯盟" aria-label="Permalink to &quot;解體的舊聯盟&quot;">​</a></h3><ul><li><strong>2M Alliance</strong>（馬士基 + MSC）：於2025年1月正式結束，合作長達十年。雙方選擇各自獨立發展戰略</li><li><strong>THE Alliance</strong>（赫伯羅特 + 長榮 + HMM + ONE）：2025年1月底赫伯羅特退出，剩餘成員重新組建</li></ul><h3 id="現行三大聯盟-合作架構" tabindex="-1">現行三大聯盟/合作架構 <a class="header-anchor" href="#現行三大聯盟-合作架構" aria-label="Permalink to &quot;現行三大聯盟/合作架構&quot;">​</a></h3><h4 id="_1-ocean-alliance-海洋聯盟-—-最大聯盟" tabindex="-1">1. Ocean Alliance（海洋聯盟）— 最大聯盟 <a class="header-anchor" href="#_1-ocean-alliance-海洋聯盟-—-最大聯盟" aria-label="Permalink to &quot;1. Ocean Alliance（海洋聯盟）— 最大聯盟&quot;">​</a></h4><ul><li><strong>成員</strong>：CMA CGM、中遠集團（COSCO）、OOCL（东方海外）、長榮（Evergreen）</li><li><strong>總運力</strong>：約500萬TEU，擁有約390艘貨櫃船</li><li><strong>市場佔有率</strong>：2025年約29%（部分分析顯示高達28.4%-31%）</li><li><strong>總容量</strong>：考慮訂單簿後超過950萬TEU，為所有聯盟中最大</li><li><strong>協議期限</strong>：已延長至2032年3月，是唯一保持原始結構的主要聯盟</li><li><strong>優勢航線</strong>：跨太平洋和亞歐航線，特別是亞太-北歐航線峰值可達41%市場份額</li></ul><h4 id="_2-gemini-cooperation-雙子星合作-—-maersk-hapag-lloyd" tabindex="-1">2. Gemini Cooperation（雙子星合作）— Maersk + Hapag-Lloyd <a class="header-anchor" href="#_2-gemini-cooperation-雙子星合作-—-maersk-hapag-lloyd" aria-label="Permalink to &quot;2. Gemini Cooperation（雙子星合作）— Maersk + Hapag-Lloyd&quot;">​</a></h4><ul><li><strong>成立時間</strong>：2025年2月正式運營（赫伯羅特於2025年1月底退出THE Alliance後加入）</li><li><strong>規模</strong>：約340艘船舶，總運力約370萬TEU（Maersk佔60%，Hapag-Lloyd佔40%）</li><li><strong>市場佔有率</strong>：2025年約21.5%-22%</li><li><strong>網絡覆蓋</strong>：34條共享主航線 + 29條穿梭航線，12個核心樞紐的樞輻模式</li><li><strong>目標</strong>：關鍵航線準點率超過90%（顯著高於行業歷史平均）</li><li><strong>趨勢</strong>：部分主要航線份額呈下降趨勢（如亞太-美國西海岸從15%降至13%，亞太-北美東岸從20%降至17%），原因是其他聯盟擴大部署</li></ul><h4 id="_3-premier-alliance-卓越聯盟-—-one-長榮-hmm" tabindex="-1">3. Premier Alliance（卓越聯盟）— ONE + 長榮 + HMM <a class="header-anchor" href="#_3-premier-alliance-卓越聯盟-—-one-長榮-hmm" aria-label="Permalink to &quot;3. Premier Alliance（卓越聯盟）— ONE + 長榮 + HMM&quot;">​</a></h4><ul><li><strong>前身</strong>：THE Alliance（赫伯羅特退出後重新命名）</li><li><strong>成員</strong>：ONE（海洋網絡快運）、長榮（Evergreen Line）、HMM（韓進海運）</li><li><strong>性質</strong>：較小的聯盟組合，透過合作維持跨洋航線競爭力</li></ul><h4 id="msc-獨立運營" tabindex="-1">MSC（獨立運營） <a class="header-anchor" href="#msc-獨立運營" aria-label="Permalink to &quot;MSC（獨立運營）&quot;">​</a></h4><ul><li>脫離2M Alliance後選擇完全獨立運營</li><li>提供直接港口對港口的廣泛服務網絡（不依賴聯盟）</li><li>以船隊規模優勢（720萬+ TEU，全球最大）和靈活策略維持市場領導地位</li></ul><h2 id="市場集中度分析" tabindex="-1">市場集中度分析 <a class="header-anchor" href="#市場集中度分析" aria-label="Permalink to &quot;市場集中度分析&quot;">​</a></h2><ul><li><strong>前六大航商合計</strong>：MSC (21.4%) + Maersk (~13-14%) + CMA CGM (12.7%) + COSCO (10.5-10.9%) + Hapag-Lloyd (~8%) + ONE (~6%) = 約75-78%的全球貨櫃運力</li><li><strong>聯盟控制</strong>：三大聯盟/合作架構合計控制約70%以上的全球貨櫃運力，市場集中度極高</li><li><strong>趨勢</strong>：市場持續向大型聯盟集中，中小型航商生存空間被壓縮</li></ul><h2 id="_2026年關鍵趨勢" tabindex="-1">2026年關鍵趨勢 <a class="header-anchor" href="#_2026年關鍵趨勢" aria-label="Permalink to &quot;2026年關鍵趨勢&quot;">​</a></h2><ol><li><strong>地緣政治影響</strong>：紅海危機和荷姆茲海峽關閉正在重塑聯盟的航線策略和市場份額</li><li><strong>過載運力風險</strong>：大量新造船訂單（特別是超大型船）可能在2027-2029年集中交船，導致運力過剩</li><li><strong>綠色轉型壓力</strong>：各聯盟和獨立航商都在投資甲醇/LNG雙燃料船舶，環保合規成本上升</li><li><strong>服務可靠性競爭</strong>：Gemini Cooperation的90%準點率目標正在推動行業整體服務標準提升</li></ol><hr><p><strong>資料來源</strong>：Maersk官方新聞稿 (2023-01)、Freightwaves (2025)、Zencargo (2025)、Kuehne+Nagel (2025)、Hapag-Lloyd官方、Wikipedia、Sea Intelligence (2025)、Container News (2025)、Maritime Gateway (2025)</p>',20)])])}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
